'library(ggplot2)

if (nrow(dataset) == 0) {
  plot.new()
  text(0.5, 0.5, "No data available", cex=1.5)
} else {
  format_k <- function(val) {
    k_val <- val / 1000
    if (k_val >= 100) {
      return(paste0(round(k_val), "K"))
    } else if (k_val >= 10) {
      return(paste0(sprintf("%.1f", k_val), "K"))
    } else {
      return(paste0(sprintf("%.2f", k_val), "K"))
    }
  }

  df <- data.frame(
    key_account = dataset[,1],
    order_lines = dataset[,2],
    order_lines_py = dataset[,3],
    account_color = dataset[,4],
    comparison_color = dataset[,5]
  )

  df <- df[order(df$order_lines, decreasing=FALSE), ]
  df$key_account <- factor(df$key_account, levels=df$key_account)
  df$label_formatted <- sapply(df$order_lines, format_k)

  theme_colors <- c("good" = "#1971c2", "bad" = "#c2255c")
  df$comparison_color_hex <- ifelse(df$comparison_color %in% names(theme_colors), 
                                     theme_colors[df$comparison_color], 
                                     "#212529")
  df$bar_color_hex <- ifelse(df$comparison_color == "bad", 
                              "#c2255c", 
                              "#CCCCCC")

  p <- ggplot(df, aes(x=key_account, y=order_lines)) +
    geom_col(aes(fill=bar_color_hex), width=0.6) +
    scale_fill_identity() +
    geom_point(aes(y=order_lines_py), color="#495057", size=9, shape=124) +
    geom_text(aes(label=label_formatted, color=comparison_color_hex), 
              hjust=-0.2, size=5, fontface="bold") +
    scale_color_identity() +
    coord_flip() +
    theme_minimal() +
    theme(
      axis.text.y = element_text(color=df$comparison_color_hex, size=10, face="bold"),
      axis.text.x = element_text(size=9, color="#6C757D"),
      axis.title = element_blank(),
      panel.grid.major.y = element_blank(),
      panel.grid.minor = element_blank(),
      plot.margin = margin(10, 40, 10, 10)
    ) +
    scale_y_continuous(expand = expansion(mult = c(0, 0.15)))

  print(p)
}'
